{
    type        box;
    boxSize     (9 1 2);
}

fieldValues
{
    T
    {
        type            uniform;
        value           uniform 300;
    }
}

boundaryConditions
{
    topWall
    {
        type            fixedValue;
        value           uniform 300;
    }

    bottomWall
    {
        type            fixedValue;
        value           uniform 305;
    }

    leftWall
    {
        type            zeroGradient;
    }

    rightWall
    {
        type            zeroGradient;
    }

    frontWall
    {
        type            empty;
    }

    backWall
    {
        type            empty;
    }
}
```

